    function commercialVisibleText(value) {
        const text = String(value ?? '');
        return COMMERCIAL_VISIBLE_ONLY_REPLACEMENTS[text] || commercialUiText(text);
    }

    function translateCommercialElementText(element) {
        if (!element || /^(INPUT|TEXTAREA|SCRIPT|STYLE|OPTION)$/i.test(element.tagName || '')) return;
        const walker = document.createTreeWalker(element, NodeFilter.SHOW_TEXT, {
            acceptNode(node) {
                const parent = node.parentElement;
                if (!parent || parent.closest('[data-commercial-translate-skip], input, textarea, script, style')) return NodeFilter.FILTER_REJECT;
                return node.nodeValue && node.nodeValue.trim() ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
            }
        });
        const nodes = [];
        while (walker.nextNode()) nodes.push(walker.currentNode);
        nodes.forEach(node => {
            const original = node.nodeValue;
            const trimmed = original.trim();
            const translated = commercialVisibleText(trimmed);
            if (!translated || translated === trimmed) return;
            node.nodeValue = original.replace(trimmed, translated);
        });
    }

    function translateCommercialVisibleText(root = document.body) {
        if (!root || typeof root.querySelectorAll !== 'function') return;
        COMMERCIAL_VISIBLE_TEXT_SELECTORS.forEach(selector => {
            if (typeof root.matches === 'function' && root.matches(selector)) translateCommercialElementText(root);
            root.querySelectorAll(selector).forEach(translateCommercialElementText);
        });
    }

    function installCommercialVisibleTextObserver(root = document.body) {
        if (!root || root.dataset?.commercialVisibleTextObserver === 'true') return;
        if (root.dataset) root.dataset.commercialVisibleTextObserver = 'true';
        let isTranslating = false;
        let pending = false;
        const run = () => {
            pending = false;
            isTranslating = true;
            translateCommercialVisibleText(root);
            isTranslating = false;
        };
        const observer = new MutationObserver(() => {
            if (isTranslating || pending) return;
            pending = true;
            window.requestAnimationFrame(run);
        });
        observer.observe(root, { childList: true, subtree: true, characterData: true });
        run();
    }

    function escapeHtml(value) {
        return String(commercialUiText(value) ?? '').replace(/[&<>"']/g, char => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[char]));
    }
    function csvFromRows(rows) {
        return (rows || []).map(row => (row || []).map(value => {
            const text = String(value ?? '');
            return /[",\n]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
        }).join(',')).join('\n');
    }
    function normalizeTicker(value) {
        const ticker = String(value || '').trim().toUpperCase();
        if (/^\d{4}$/.test(ticker)) return `${ticker}.TW`;
        return ticker || '2330.TW';
    }
    function readCommercialParams() {
        return new URLSearchParams(window.location.search || '');
    }
    function replaceCommercialQuery(state) {
        if (!window.history?.replaceState) return;
        const params = new URLSearchParams(window.location.search || '');
        Object.entries(state || {}).forEach(([key, value]) => {
            const text = String(value ?? '').trim();
            if (text) params.set(key, text);
            else params.delete(key);
        });
        const query = params.toString();
        window.history.replaceState({}, '', `${window.location.pathname}${query ? `?${query}` : ''}${window.location.hash || ''}`);
    }
    function validCommercialChoice(value, allowed, fallback) {
        const text = String(value || '');
        return allowed.includes(text) ? text : fallback;
    }
    function commercialNumberParam(params, key, fallback, min, max) {
        if (!params.has(key)) return fallback;
        const value = Number(params.get(key));
        if (!Number.isFinite(value)) return fallback;
        return Math.max(min, Math.min(max, Math.round(value)));
    }
