    function commercialWorkspaceRecentSymbols(pageName, ticker) {
        const normalized = normalizeTicker(ticker || '2330.TW');
        const primarySection = commercialWorkspacePrimarySection(pageName);
        const source = [
            { ticker: normalized, company: '目前股票', status: '快照', returnPct: 0 },
            ...fallbackTickers
        ];
        const seen = new Set();
        return source
            .map(item => ({ ...item, ticker: normalizeTicker(item.ticker) }))
            .filter(item => {
                if (seen.has(item.ticker)) return false;
                seen.add(item.ticker);
                return true;
            })
            .slice(0, 5)
            .map((item, index) => ({
                ...item,
                active: item.ticker === normalized,
                label: index === 0 && item.ticker === normalized ? '目前股票' : (item.status || '追蹤中'),
                href: commercialPageUrl(pageName, item.ticker) + `#${primarySection}`,
                metric: Number.isFinite(Number(item.returnPct)) ? pct(Number(item.returnPct)) : '快照'
            }));
    }
    function commercialWorkspaceSymbolSuggestions(pageName, ticker, context = {}) {
        const normalized = normalizeTicker(ticker || '2330.TW');
        const activeTarget = commercialContextTargetId(pageName);
        const pageMetric = activeTarget === 'stock' ? '快照' : activeTarget === 'portfolio' ? '投組影響' : '追蹤表列';
        const knownCompanies = {
            '2317.TW': '鴻海 / Hon Hai',
            '2454.TW': '聯發科 / MediaTek',
            '2412.TW': '中華電 / Chunghwa Telecom',
            AAPL: 'Apple',
            MSFT: 'Microsoft',
            NVDA: 'NVIDIA'
        };
        const aliasMap = WORKBENCH_SEARCH_ALIASES.reduce((map, item) => {
            map[normalizeTicker(item.ticker)] = item.aliases || [];
            return map;
        }, {});
        const source = [
            { ticker: normalized, company: context.company || '目前股票', status: '打開股票', returnPct: 0 },
            ...fallbackTickers,
            ...WORKBENCH_SEARCH_ALIASES.map(item => ({ ticker: normalizeTicker(item.ticker), company: knownCompanies[normalizeTicker(item.ticker)] || item.aliases?.[0] || item.ticker, status: '打開股票', returnPct: 0 }))
        ];
        const seen = new Set();
        return source
            .map(item => {
                const tickerValue = normalizeTicker(item.ticker);
                const aliases = aliasMap[tickerValue] || [];
                return {
                    ...item,
                    ticker: tickerValue,
                    company: item.company || knownCompanies[tickerValue] || tickerValue,
                    aliases,
                    metric: Number.isFinite(Number(item.returnPct)) && Number(item.returnPct) !== 0 ? pct(Number(item.returnPct)) : pageMetric
                };
            })
            .filter(item => {
                if (seen.has(item.ticker)) return false;
                seen.add(item.ticker);
                return true;
            })
            .slice(0, 8)
            .map(item => ({
                ...item,
                active: item.ticker === normalized,
                search: `${item.ticker} ${item.company || ''} ${(item.aliases || []).join(' ')} 打開股票 ${pageMetric}`.toLowerCase()
            }));
    }
