    function commercialPositionMetric(label, value, detail, tone = '') {
        return { label, value: value ?? 'N/A', detail: detail || '', tone };
    }
    function commercialPositionLot(ticker, label, shares, cost, value, detail, tone = '') {
        return { ticker, label, shares, cost, value, detail: detail || '', tone };
    }
    function commercialPositionMoney(value) {
        const number = Number(value);
        if (!Number.isFinite(number)) return 'N/A';
        const abs = Math.abs(number);
        const prefix = number < 0 ? '-' : '';
        if (abs >= 1000000) return `${prefix}${(abs / 1000000).toFixed(1)}M`;
        if (abs >= 1000) return `${prefix}${(abs / 1000).toFixed(1)}K`;
        return `${prefix}${abs.toFixed(0)}`;
    }
    function commercialPositionLedgerCsv(config, activeMode) {
        const escapeCsv = value => `"${String(value ?? '').replaceAll('"', '""')}"`;
        const selected = (config?.modes || []).find(mode => mode.id === activeMode) || (config?.modes || [])[0] || {};
        const rows = [
            ['Mode', selected.label || activeMode, selected.detail || ''],
            ...(config?.metrics || []).map(metric => [metric.label, metric.value, metric.detail || '']),
            ...(config?.lots || []).map(lot => [lot.ticker || '', lot.label || '', lot.shares || '', lot.cost || '', lot.value || '', lot.detail || ''])
        ];
        return [config?.title || 'Position Ledger', 'Field,Value,Detail,Cost,Market Value,Note', ...rows.map(row => row.map(escapeCsv).join(','))].join('\n');
    }
