            const source = event.target.closest('.commercial-import-source[data-commercial-import-source]')?.dataset.commercialImportSource;
            if (source) {
                writeCommercialMemory(`import-center-${scope}`, { ...preference, source });
                renderCommercialImportCenter(root, typeof configFactory === 'function' ? configFactory() : config, source);
                return;
            }
            const activeSource = root.dataset.commercialImportActive || preference.source || config?.defaultSource || 'broker-csv';
            const target = event.target.closest('[data-commercial-import-target]')?.dataset.commercialImportTarget || config?.target || '';
            const csvInput = root.querySelector('[data-commercial-import-csv]');
