    function bindCommercialTaxIncomeCenter(root, scope, configFactory) {
        if (!root || root.dataset.commercialTaxBound === 'true') return;
        root.dataset.commercialTaxBound = 'true';
        root.addEventListener('click', event => {
            const config = root.__commercialTaxConfig || (typeof configFactory === 'function' ? configFactory() : {});
            const preference = commercialTaxPreference(scope, config?.defaultView || 'income');
            const view = event.target.closest('.commercial-tax-view[data-commercial-tax-view]')?.dataset.commercialTaxView;
            if (view) {
                writeCommercialMemory(`tax-income-${scope}`, { ...preference, view });
                renderCommercialTaxIncomeCenter(root, typeof configFactory === 'function' ? configFactory() : config, view);
                return;
            }
            const activeView = root.dataset.commercialTaxActive || preference.view || config?.defaultView || 'income';
            if (event.target.closest('[data-commercial-tax-save]')) {
                writeCommercialMemory(`tax-income-${scope}`, { ...preference, view: activeView, savedAt: new Date().toLocaleString('zh-TW') });
                showCommercialFeedback(root, 'Tax view saved');
                return;
            }
            if (event.target.closest('[data-commercial-tax-export]')) {
                writeCommercialMemory(`tax-income-${scope}`, { ...preference, view: activeView, exportedAt: new Date().toLocaleString('zh-TW') });
                downloadCommercialText(`onstock-${scope}-tax-pack.csv`, commercialTaxReportCsv(config, activeView));
                showCommercialFeedback(root, 'Tax pack exported');
                return;
            }
            const target = event.target.closest('[data-commercial-tax-target]')?.dataset.commercialTaxTarget;
            if (target) scrollCommercialTaskTarget(target);
        });
    }
