    function bindCommercialCopilotPanel(root, scope, configFactory) {
        if (!root || root.dataset.commercialCopilotBound === 'true') return;
        root.dataset.commercialCopilotBound = 'true';
        root.addEventListener('click', async event => {
            const config = root.__commercialCopilotConfig || (typeof configFactory === 'function' ? configFactory() : {});
            const preference = commercialCopilotPreference(scope, config?.defaultPrompt || 'why');
            const prompt = event.target.closest('.commercial-copilot-prompt[data-commercial-copilot-prompt]')?.dataset.commercialCopilotPrompt;
            if (prompt) {
                writeCommercialMemory(`copilot-${scope}`, { ...preference, prompt });
                renderCommercialCopilotPanel(root, typeof configFactory === 'function' ? configFactory() : config, prompt);
                return;
            }
            const activePrompt = root.dataset.commercialCopilotActive || preference.prompt || config?.defaultPrompt || 'why';
            if (event.target.closest('[data-commercial-copilot-copy]')) {
                writeCommercialMemory(`copilot-${scope}`, { ...preference, prompt: activePrompt, copiedAt: new Date().toLocaleString('zh-TW') });
                await copyCommercialText(commercialCopilotShareText(config, activePrompt), root, '助理摘要已複製');
                return;
            }
            if (event.target.closest('[data-commercial-copilot-save]')) {
                writeCommercialMemory(`copilot-${scope}`, { ...preference, prompt: activePrompt, savedAt: new Date().toLocaleString('zh-TW') });
                showCommercialFeedback(root, '助理提問已儲存');
                return;
            }
            const target = event.target.closest('[data-commercial-copilot-target]')?.dataset.commercialCopilotTarget;
            if (target) scrollCommercialTaskTarget(target);
        });
    }
