    function commercialCompetitiveLensPreference(scope, fallbackLens) {
        const saved = readCommercialMemory(`competitive-lens-${scope}`);
        return {
            lens: saved.lens || fallbackLens || 'summary',
            savedAt: saved.savedAt || '',
            copiedAt: saved.copiedAt || '',
            exportedAt: saved.exportedAt || '',
            openedAt: saved.openedAt || ''
        };
    }
    function commercialCompetitiveLensMetric(label, value, detail, score, tone = '') {
        const numericScore = Number(score);
        return {
            label,
            value: value ?? 'N/A',
            detail: detail || '',
            score: Number.isFinite(numericScore) ? Math.max(0, Math.min(100, Math.round(numericScore))) : 50,
            tone
        };
    }
    function commercialCompetitiveLensStage(id, label, detail, target, status, tone = '') {
        return { id, label, detail: detail || '', target: target || '', status: status || 'Ready', tone };
    }
    function commercialCompetitiveLensSummary(config, activeLens) {
        const selected = (config?.stages || []).find(item => item.id === activeLens) || (config?.stages || [])[0] || {};
        const stages = (config?.stages || []).map(item => `${item.label}: ${item.status} · ${item.detail}`).join('\n');
        const metrics = (config?.metrics || []).map(item => `${item.label}: ${item.value} · ${item.score}/100 (${item.detail})`).join('\n');
        return [
            config?.title || 'Competitive Lens',
            `Selected Lens: ${selected.label || activeLens || 'summary'}`,
            `Purpose: ${config?.detail || ''}`,
            `View: ${config?.status || ''}`,
            `Lens Options:\n${stages || 'No lens options'}`,
            `Metrics:\n${metrics || 'No metrics'}`,
            `Link: ${window.location.href}`
        ].join('\n');
    }
    function commercialCompetitiveLensCsv(config, activeLens) {
        const selected = (config?.stages || []).find(item => item.id === activeLens) || (config?.stages || [])[0] || {};
        return csvFromRows([
            ['Section', 'Label', 'Value', 'Detail', 'Score'],
            ['Lens', config?.title || 'Competitive Lens', selected.label || activeLens || '', config?.detail || '', ''],
            ['Selected', selected.label || '', selected.status || '', selected.detail || '', ''],
            ...(config?.stages || []).map(item => ['Stage', item.label || '', item.status || '', item.detail || '', '']),
            ...(config?.metrics || []).map(item => ['Metric', item.label || '', item.value ?? '', item.detail || '', item.score ?? ''])
        ]);
    }
    function renderCompetitiveBars(metrics) {
        return `
            <div class="commercial-competitive-bars" aria-label="Competitive Lens Metrics">
                ${metrics.map(item => `
                    <div class="commercial-competitive-bar ${escapeHtml(item.tone || '')}">
                        <span>${escapeHtml(item.label || '')}</span>
                        <div class="commercial-competitive-bar-fill" style="--score: ${escapeHtml(item.score || 0)}%"></div>
                        <strong>${escapeHtml(item.value ?? 'N/A')}</strong>
                        <em>${escapeHtml(item.detail || '')}</em>
                    </div>
                `).join('')}
            </div>
        `;
    }
    function renderCompetitiveRadar(metrics) {
        const points = (metrics || []).slice(0, 5).map((item, index, list) => {
            const angle = (-90 + (360 / Math.max(list.length, 1)) * index) * Math.PI / 180;
            const radius = 12 + (Number(item.score) || 0) * 0.36;
            const x = 50 + Math.cos(angle) * radius;
            const y = 50 + Math.sin(angle) * radius;
            return { ...item, x: Math.max(10, Math.min(90, x)), y: Math.max(10, Math.min(90, y)) };
        });
        return `
            <div class="commercial-competitive-radar" aria-label="Competitive Lens">
                ${points.map(item => `
                    <div class="commercial-competitive-radar-point ${escapeHtml(item.tone || '')}" style="--x: ${escapeHtml(item.x.toFixed(1))}; --y: ${escapeHtml(item.y.toFixed(1))}">
                        <span>${escapeHtml(item.label || '')}</span>
                        <strong>${escapeHtml(item.value ?? 'N/A')}</strong>
                    </div>
                `).join('')}
            </div>
            ${renderCompetitiveBars(metrics)}
        `;
    }
    function renderCompetitiveReturnStack(metrics) {
        return `
            <div class="commercial-competitive-return-stack" aria-label="Return Components">
                ${metrics.map(item => `
                    <div class="commercial-competitive-return-segment ${escapeHtml(item.tone || '')}" style="--weight: ${escapeHtml(Math.max(1, item.score || 1))}">
                        <span>${escapeHtml(item.label || '')}</span>
                        <strong>${escapeHtml(item.value ?? 'N/A')}</strong>
                        <span>${escapeHtml(item.detail || '')}</span>
                    </div>
                `).join('')}
            </div>
            ${renderCompetitiveBars(metrics)}
        `;
    }
