        const positiveCount = sourceRows.filter(row => Number(row.returnPct) > 0).length;
        return {
            scope: 'workbench',
            title: 'Watchlist Insight Digest',
            detail: `${shortTicker(ticker)} · combine watchlist news, filings, rating changes and price alerts into one user-ready digest`,
            defaultChannel: alertCount ? 'price-alerts' : 'news-filings',
            target: 'commercial-workbench-event-queue',
            status: `${sourceRows.length} symbols · ${alertCount} alert items`,
            cadence: ['Morning', 'Close', 'Push-ready', activeView || 'decision'],
            channels: [
                commercialInsightDigestChannel('news-filings', 'News & Filings', 'watchlist news, filings and transcript items specific to tracked names', 'commercial-workbench-event-queue', `${sourceRows.length} names`),
                commercialInsightDigestChannel('rating-changes', 'Rating Changes', 'surface recommendation shifts and report rerun candidates', 'commercial-workbench-change-radar', `${positiveCount} positive`, positiveCount ? 'is-positive' : ''),
                commercialInsightDigestChannel('price-alerts', 'Price Alerts', 'batch alert candidates across the visible watchlist', 'commercial-workbench-alert-center', `${alertCount} alerts`, alertCount ? 'is-warning' : 'is-positive'),
                commercialInsightDigestChannel('earnings-queue', 'Earnings Queue', 'prepare calendar-driven review before market events', 'commercial-workbench-event-calendar', currentFilter || 'all')
            ],
            items: [
                commercialInsightDigestItem('Tracked Symbols', String(sourceRows.length), 'visible decision universe', 'commercial-workbench-table', sourceRows.length ? 'is-positive' : 'is-warning'),
                commercialInsightDigestItem('Alert Load', String(alertCount), 'items that should be pushed into today inbox', 'commercial-workbench-alert-center', alertCount ? 'is-warning' : 'is-positive'),
                commercialInsightDigestItem('Positive Names', String(positiveCount), 'watchlist names above recommendation price', 'commercial-workbench-score-strip', positiveCount ? 'is-positive' : ''),
                commercialInsightDigestItem('Digest Route', currentFilter || 'all', 'current filter decides what is included', 'commercial-workbench-section-nav')
            ]
        };
