        const change = Number(snapshot?.market_session?.change_pct ?? snapshot?.quote?.change_pct);
        const upside = Number(snapshot?.analyst_outlook?.target?.upside_pct ?? snapshot?.valuation?.analyst_target?.upside_pct);
