            detail: `${ticker} · explain the move, earnings prep, rating watch and transcript notes before opening long reports`,
            defaultChannel: Number.isFinite(change) && Math.abs(change) > 1 ? 'move-explainer' : 'earnings-prep',
            target: 'commercial-stock-content',
            status: `${currentTab || 'overview'} · ${activeScenario || 'base'} · ${activeCoverage || 'alerts'}`,
