            title: 'Watchlist What-If Lab',
            detail: `${shortTicker(ticker)} · test market, earnings and quality-filter changes before changing the decision table`,
            defaultScenario: alertCount ? 'market-shock' : 'quality-filter',
            target: 'commercial-workbench-risk-lab',
