            assumptions: ['Watchlist scope', 'Snapshot rerun', 'Report impact', 'Saved view'],
            scenarios: [
                commercialScenarioOption('market-shock', 'Market Shock', 'stress all visible tickers with a broad downside move', 'commercial-workbench-risk-lab', `${alertCount} flags`, alertCount ? 'is-warning' : ''),
                commercialScenarioOption('earnings-surprise', 'Earnings Surprise', 'prioritize event-driven names and rerun reports after earnings', 'commercial-workbench-event-queue', `${sourceRows.length} names`),
                commercialScenarioOption('quality-filter', 'Quality Filter', 'hide weak data-quality rows and surface durable candidates', 'commercial-workbench-grid-lab', `${positiveCount} leaders`, positiveCount ? 'is-positive' : ''),
                commercialScenarioOption('rotation-play', 'Rotation Play', 'compare active ticker against the current watchlist leaders', 'commercial-workbench-compare-dock', pct(avgReturn))
            ],
