    function commercialContextMetricTone(value) {
        const text = String(value ?? '').toLowerCase();
        const number = Number(value);
        if (Number.isFinite(number)) {
            if (number > 0) return 'is-positive';
            if (number < 0) return 'is-negative';
        }
        if (/警示|重跑|missing|gap|risk|bear|down|negative/.test(text)) return 'is-warning';
        if (/買|buy|up|positive|strong|live/.test(text)) return 'is-positive';
        return '';
    }
    function defaultCommercialContextMetrics(ticker) {
        return [
            { label: 'Ticker', value: normalizeTicker(ticker), detail: '研究脈絡', tone: '' },
            { label: 'Mode', value: 'Ready', detail: '可跨頁保留', tone: 'is-positive' }
        ];
    }
    function quoteContextMetrics(snapshot, row) {
        const session = snapshot?.market_session || {};
        const analyst = snapshot?.analyst_outlook || {};
        const price = snapshot?.quote?.price_label || numberLabel(session.current_price || snapshot?.quote?.price);
        const change = Number(session.change_pct);
        const upside = Number(analyst.target?.upside_pct);
        const rowReturn = Number(row?.returnPct);
        const rating = row?.recommendation || analyst.consensus?.recommendation_label || analyst.label || '待判斷';
        const targetValue = Number.isFinite(upside) ? pct(upside) : (Number.isFinite(rowReturn) ? pct(rowReturn) : 'N/A');
        return [
            { label: 'Price', value: price || 'N/A', detail: session.direction ? String(session.direction).toUpperCase() : '最新價', tone: commercialContextMetricTone(change) },
            { label: 'Day Change', value: Number.isFinite(change) ? pct(change) : 'N/A', detail: '盤中變動', tone: commercialContextMetricTone(change) },
            { label: 'Decision', value: rating, detail: row?.status || analyst.label || '共識評等', tone: commercialContextMetricTone(row?.status || rating) },
            { label: 'Target Gap', value: targetValue, detail: Number.isFinite(upside) ? '目標價上行' : '建議後報酬', tone: commercialContextMetricTone(Number.isFinite(upside) ? upside : rowReturn) }
        ];
    }
    function portfolioContextMetrics(payload, contextTicker, activeLens, activeScenario, activeTargetModel) {
        const normalized = normalizeTicker(contextTicker || '2330.TW');
        const top = payload?.concentration?.top_position || {};
        const sectorWeights = payload?.concentration?.sector_weights || {};
        const topSector = Object.entries(sectorWeights).sort((a, b) => Number(b[1]) - Number(a[1]))[0] || ['Sector', 'N/A'];
        const invalidated = payload?.thesis_health?.invalidated || [];
        const missing = payload?.thesis_health?.missing || [];
        const thesisCount = invalidated.length + missing.length;
        const topWeight = Number(top.weight_pct);
        const isTop = normalizeTicker(top.ticker) === normalized;
        const model = PORTFOLIO_TARGET_MODELS[activeTargetModel]?.label || activeTargetModel || 'Model';
        return [
            { label: 'Holding', value: isTop && Number.isFinite(topWeight) ? `${topWeight.toFixed(0)}%` : normalized, detail: isTop ? 'Top position' : `Top ${top.ticker || 'N/A'}`, tone: isTop ? 'is-warning' : '' },
            { label: 'Exposure', value: `${topSector[0]} ${Number.isFinite(Number(topSector[1])) ? `${Number(topSector[1]).toFixed(0)}%` : topSector[1]}`, detail: '最大產業曝險', tone: commercialContextMetricTone(topSector[1]) },
            { label: 'Thesis Gaps', value: String(thesisCount), detail: `${invalidated.length} invalidated / ${missing.length} missing`, tone: thesisCount ? 'is-warning' : 'is-positive' },
            { label: 'Model', value: model, detail: `${activeLens} · ${activeScenario}`, tone: commercialContextMetricTone(activeScenario) }
        ];
    }
