        const rawSteps = config?.steps || [];
        const steps = rawSteps.map(step => ({ ...step, complete: Boolean(step.complete || preference.done.includes(step.id)) }));
        const completeCount = steps.filter(step => step.complete).length;
        const percent = steps.length ? Math.round((completeCount / steps.length) * 100) : 0;
        const selected = steps.find(step => step.id === preference.activeStep) || steps.find(step => !step.complete) || steps[0] || {};
