    function commercialEvidenceBinderPreference(scope, fallbackEvidence) {
        const saved = readCommercialMemory(`evidence-binder-${scope}`);
        return {
            evidence: saved.evidence || fallbackEvidence || 'source',
            pinned: Array.isArray(saved.pinned) ? saved.pinned : [],
            savedAt: saved.savedAt || ''
        };
    }
    function commercialEvidenceBinderText(config, activeEvidence) {
        const evidence = config?.evidence || [];
        const selected = evidence.find(item => item.id === activeEvidence) || evidence[0] || {};
        return [
            config?.title || '證據夾',
            `${selected.label || activeEvidence}: ${selected.status || 'N/A'}`,
            selected.detail || '',
            `來源: ${selected.source || 'N/A'}`,
            `資料新鮮度: ${selected.timestamp || config?.freshness || 'N/A'}`
        ].filter(Boolean).join('\n');
    }
    function commercialEvidenceBinderCsv(config, activeEvidence) {
        const escapeCsv = value => `"${String(value ?? '').replaceAll('"', '""')}"`;
        const evidence = config?.evidence || [];
        const selected = evidence.find(item => item.id === activeEvidence) || evidence[0] || {};
        const rows = [
            ['目前證據', selected.label || activeEvidence, selected.status || 'N/A', selected.source || ''],
            ['資料新鮮度', selected.timestamp || config?.freshness || 'N/A', config?.dataSource || '資料來源', config?.decision || ''],
            ...evidence.map(item => [item.label, item.status || 'N/A', item.timestamp || 'N/A', item.source || item.detail || ''])
        ];
        return [config?.title || '證據夾', '欄位,狀態,新鮮度,來源', ...rows.map(row => row.map(escapeCsv).join(','))].join('\n');
    }
    function evidenceTone(status) {
        const text = String(status || '').toLowerCase();
        if (/live|ready|current|fresh|verified|complete|即時|就緒|目前|新鮮|已驗證|完整|可用/.test(text)) return 'is-live';
        if (/fallback|stale|missing|gap|review|watch|備援|過期|缺漏|缺口|複查|觀察|待補/.test(text)) return 'is-warning';
        return '';
    }
    function evidenceBinderItem(id, label, status, detail, target, source, timestamp) {
        return {
            id,
            label,
            status,
            detail,
            target,
            source,
            timestamp,
            tone: evidenceTone(status)
        };
    }
    function renderCommercialEvidenceBinder(root, config, activeEvidence) {
        if (!root) return;
        const evidence = config?.evidence || [];
        const fallbackEvidence = config?.defaultEvidence || evidence[0]?.id || 'source';
        const preference = commercialEvidenceBinderPreference(config?.scope || 'workbench', fallbackEvidence);
        const selected = evidence.find(item => item.id === activeEvidence) || evidence.find(item => item.id === fallbackEvidence) || evidence[0] || {};
        const pinned = new Set(preference.pinned || []);
        root.__commercialEvidenceConfig = config;
        root.className = `commercial-evidence-binder ${config?.tone || ''}`.trim();
        root.dataset.commercialEvidenceActive = selected.id || fallbackEvidence;
        root.innerHTML = `
            <div class="commercial-evidence-copy">
                <span>證據夾</span>
                <strong>${escapeHtml(config?.title || '證據夾')}</strong>
                <em>${escapeHtml(config?.detail || '確認目前決策背後的來源、新鮮度與可追溯證據。')}</em>
                <span class="commercial-evidence-status" data-commercial-feedback role="status">${escapeHtml(config?.status || '')}</span>
            </div>
            <div class="commercial-evidence-summary" aria-label="證據夾">
                <span>資料來源</span>
                <strong>${escapeHtml(config?.dataSource || selected.source || 'N/A')}</strong>
                <em>資料新鮮度 · ${escapeHtml(selected.timestamp || config?.freshness || 'N/A')}</em>
                <b>${escapeHtml(selected.detail || config?.decision || '')}</b>
            </div>
            <div class="commercial-evidence-source-grid">
                ${evidence.map(item => `
                    <button class="commercial-evidence-source ${item.id === selected.id ? 'is-active' : ''} ${escapeHtml(item.tone || '')} ${pinned.has(item.id) ? 'is-pinned' : ''}" type="button" data-commercial-evidence-choice="${escapeHtml(item.id)}" aria-pressed="${item.id === selected.id}">
                        <span>${escapeHtml(item.label || '')}</span>
                        <strong>${escapeHtml(item.status || 'N/A')}</strong>
                        <em>${escapeHtml(item.timestamp || '')}</em>
                        <b>${escapeHtml(pinned.has(item.id) ? '已釘選' : (item.source || ''))}</b>
                    </button>
                `).join('')}
            </div>
            <div class="commercial-evidence-actions">
                <button class="commercial-evidence-action is-primary" type="button" data-commercial-evidence-target="${escapeHtml(selected.target || config?.target || '')}">打開證據</button>
                <button class="commercial-evidence-action" type="button" data-commercial-evidence-pin>釘選證據</button>
                <button class="commercial-evidence-action" type="button" data-commercial-evidence-export>匯出證據夾</button>
            </div>
        `;
    }
    function bindCommercialEvidenceBinder(root, scope, configFactory) {
        if (!root || root.dataset.commercialEvidenceBinderBound === 'true') return;
        root.dataset.commercialEvidenceBinderBound = 'true';
        root.addEventListener('click', event => {
            const config = root.__commercialEvidenceConfig || (typeof configFactory === 'function' ? configFactory() : {});
            const preference = commercialEvidenceBinderPreference(scope, config?.defaultEvidence || 'source');
            const choice = event.target.closest('.commercial-evidence-source[data-commercial-evidence-choice]')?.dataset.commercialEvidenceChoice;
            if (choice) {
                writeCommercialMemory(`evidence-binder-${scope}`, { ...preference, evidence: choice });
                renderCommercialEvidenceBinder(root, typeof configFactory === 'function' ? configFactory() : config, choice);
                return;
            }
            const activeEvidence = root.dataset.commercialEvidenceActive || preference.evidence || config?.defaultEvidence || 'source';
            if (event.target.closest('[data-commercial-evidence-target]')) {
                const item = (config?.evidence || []).find(entry => entry.id === activeEvidence) || {};
                scrollCommercialTaskTarget(item.target || config?.target || '');
                showCommercialFeedback(root, '證據已打開');
                return;
            }
            if (event.target.closest('[data-commercial-evidence-pin]')) {
                const pinned = Array.from(new Set([...(preference.pinned || []), activeEvidence].filter(Boolean)));
                writeCommercialMemory(`evidence-binder-${scope}`, { ...preference, evidence: activeEvidence, pinned, savedAt: new Date().toLocaleString('zh-TW') });
                renderCommercialEvidenceBinder(root, { ...(typeof configFactory === 'function' ? configFactory() : config), status: '證據已釘選' }, activeEvidence);
                return;
            }
            if (event.target.closest('[data-commercial-evidence-export]')) {
                downloadCommercialText(`onstock-${scope}-evidence-binder.csv`, commercialEvidenceBinderCsv(config, activeEvidence));
                showCommercialFeedback(root, '證據夾已匯出');
            }
        });
    }
    function workbenchEvidenceBinderConfig(rows, activeTicker, activeView, currentFilter) {
        const sourceRows = rows && rows.length ? rows : fallbackTickers;
        const ticker = normalizeTicker(activeTicker || sourceRows[0]?.ticker || '2330.TW');
        const selectedRow = sourceRows.find(row => normalizeTicker(row.ticker) === ticker) || sourceRows[0] || {};
        const alertCount = sourceRows.filter(row => /警示|重跑|觀察/.test(`${row.status || ''}${row.recommendation || ''}`)).length;
        const evidence = [
            evidenceBinderItem('decision', '決策追蹤', selectedRow.status || '就緒', `${ticker} 列的建議、狀態與報酬來自每日決策追蹤表`, 'commercial-workbench-table', '決策追蹤 API', '今日'),
            evidenceBinderItem('snapshot', '快照報價', selectedRow.price ? '新鮮' : '複查', '釘選快照與報價脈絡固定在表格上方', 'commercial-workbench-snapshot-inspector', '股票快照 API', selectedRow.price ? '即時/備援' : '待補報價'),
            evidenceBinderItem('news', '新聞/公告', alertCount ? '觀察' : '就緒', `${alertCount} 個連動警示事件需要複查`, 'commercial-workbench-event-queue', '新聞/事件隊列', currentFilter || '全部'),
            evidenceBinderItem('report', '報告包', activeView === 'valuation' ? '完整' : '就緒', '可交付報告包能匯出追蹤表研究脈絡', 'commercial-workbench-report-pack', '研究包', activeView || '決策')
        ];
        return {
            scope: 'workbench',
            title: '追蹤表證據夾',
            detail: `${ticker} · 目前追蹤表決策背後的證據`,
            defaultEvidence: alertCount ? 'news' : 'decision',
            target: 'commercial-workbench-table',
            dataSource: '資料來源 · 決策追蹤 + 快照',
            freshness: `${sourceRows.length} 列 · ${currentFilter || '全部'} 篩選`,
            decision: selectedRow.recommendation || '決策待確認',
            evidence
        };
    }
