    function bindCommercialPrimaryCustomizeStrip(root) {
        if (!root || root.dataset.commercialPrimaryCustomizeBound === 'true') return;
        root.dataset.commercialPrimaryCustomizeBound = 'true';
        root.addEventListener('click', event => {
            const command = event.target.closest('[data-commercial-primary-customize-target], [data-commercial-primary-monitor-target]');
            if (!command || !root.contains(command)) return;
            const target = command.dataset.commercialPrimaryCustomizeTarget || command.dataset.commercialPrimaryMonitorTarget || '';
            const status = command.dataset.commercialPrimaryCustomizeStatus || command.dataset.commercialPrimaryMonitorStatus || command.textContent?.trim() || 'Customize';
            const actionId = command.dataset.commercialPrimaryCustomizeAction || '';
            if (target) scrollCommercialTaskTarget(target);
            root.dispatchEvent(new CustomEvent('commercial-primary-customize-action', {
                bubbles: true,
                detail: { actionId, target, status }
            }));
            const output = root.querySelector('.commercial-primary-customize-status');
            if (output) {
                output.hidden = false;
                output.style.display = 'grid';
                output.textContent = status ? `Opened ${status}` : 'Opened custom workspace';
            }
        });
    }
