    function commercialCommandAttributes(item) {
        const attributes = [];
        const pairs = [
            ['workbenchView', 'data-commercial-workbench-command-view'],
            ['workbenchFilter', 'data-commercial-workbench-command-filter'],
            ['workbenchColumns', 'data-commercial-workbench-command-columns'],
            ['workbenchAction', 'data-commercial-workbench-command-action'],
            ['stockTab', 'data-commercial-stock-command-tab'],
            ['stockTarget', 'data-commercial-stock-command-target'],
            ['portfolioLens', 'data-commercial-portfolio-command-lens'],
            ['portfolioModel', 'data-commercial-portfolio-command-model'],
            ['portfolioTarget', 'data-commercial-portfolio-command-target']
        ];
        pairs.forEach(([key, attribute]) => {
            if (item?.[key]) attributes.push(`${attribute}="${escapeHtml(item[key])}"`);
        });
        return attributes.join(' ');
    }
