    function commercialDefaultModulePins(modules) {
        return (modules || []).filter(module => module.pinned).map(module => module.id).slice(0, 3);
    }
    function commercialModuleLayoutPreference(scope, fallbackPins) {
        const saved = readCommercialMemory(`module-layout-${scope}`);
        const pins = Array.isArray(saved.pins) ? saved.pins.filter(Boolean).slice(0, 3) : [];
        return { pins: pins.length ? pins : [...(fallbackPins || [])] };
    }
    function renderCommercialModulePinboard(root, config, savedPins = []) {
        if (!root) return;
        const modules = config?.modules || [];
        const pins = savedPins.length ? savedPins : commercialDefaultModulePins(modules);
        const pinnedSet = new Set(pins);
        const orderedModules = [...modules].sort((a, b) => {
            const aPinned = pinnedSet.has(a.id);
            const bPinned = pinnedSet.has(b.id);
            if (aPinned !== bPinned) return aPinned ? -1 : 1;
            return pins.indexOf(a.id) - pins.indexOf(b.id);
        });
        root.className = `commercial-module-pinboard ${config?.tone || ''}`.trim();
        root.innerHTML = `
            <div class="commercial-module-copy">
                <span>Widget Layout</span>
                <strong>${escapeHtml(config?.title || 'Pinned Modules')}</strong>
                <em>${escapeHtml(config?.detail || 'Pin modules you want near the top of this workflow.')}</em>
            </div>
            <div class="commercial-module-grid" aria-label="Pinned Modules">
                ${orderedModules.map(module => {
                    const isPinned = pinnedSet.has(module.id);
                    return `
                        <div class="commercial-module-card ${isPinned ? 'is-pinned' : ''}">
                            <div>
                                <span>${isPinned ? 'Pinned Modules' : 'Available Module'}</span>
                                <strong>${escapeHtml(module.label)}</strong>
                                <em>${escapeHtml(module.detail || '')}</em>
                            </div>
                            <div class="commercial-module-actions">
                                <button class="commercial-module-action is-primary" type="button" data-commercial-module-target="${escapeHtml(module.target)}">Open</button>
                                <button class="commercial-module-action" type="button" data-commercial-module-pin="${escapeHtml(module.id)}" aria-pressed="${isPinned}">${isPinned ? 'Pinned' : 'Pin to top'}</button>
                            </div>
                        </div>
                    `;
                }).join('')}
            </div>
            <div class="commercial-module-actions">
                <button class="commercial-module-action is-primary" type="button" data-commercial-module-save>Save Layout</button>
                <button class="commercial-module-action" type="button" data-commercial-module-reset>Reset Layout</button>
                <span class="commercial-memory-status" data-commercial-feedback>${escapeHtml(config?.message || '')}</span>
            </div>
        `;
    }
    function bindCommercialModulePinboard(root, scope, configFactory) {
        if (!root || root.dataset.commercialModulePinboardBound === 'true') return;
        root.dataset.commercialModulePinboardBound = 'true';
        root.addEventListener('click', event => {
            const config = typeof configFactory === 'function' ? configFactory() : {};
            const modules = config?.modules || [];
            const fallbackPins = commercialDefaultModulePins(modules);
            const currentPins = commercialModuleLayoutPreference(scope, fallbackPins).pins;
            const target = event.target.closest('[data-commercial-module-target]')?.dataset.commercialModuleTarget;
            const pinId = event.target.closest('[data-commercial-module-pin]')?.dataset.commercialModulePin;
            if (target) {
                scrollCommercialTaskTarget(target);
                return;
            }
            if (pinId) {
                const nextPins = currentPins.includes(pinId)
                    ? currentPins.filter(id => id !== pinId)
                    : [pinId, ...currentPins.filter(id => id !== pinId)].slice(0, 3);
                writeCommercialMemory(`module-layout-${scope}`, { pins: nextPins });
                renderCommercialModulePinboard(root, { ...config, message: 'Layout saved' }, nextPins);
                return;
            }
            if (event.target.closest('[data-commercial-module-save]')) {
                writeCommercialMemory(`module-layout-${scope}`, { pins: currentPins });
                showCommercialFeedback(root, 'Layout saved');
                return;
            }
            if (event.target.closest('[data-commercial-module-reset]')) {
                writeCommercialMemory(`module-layout-${scope}`, { pins: fallbackPins });
                renderCommercialModulePinboard(root, { ...config, message: 'Layout reset' }, fallbackPins);
            }
        });
    }
