    function ruleControlWidth(value, fallback = 52) {
        const number = Number(value);
        if (!Number.isFinite(number)) return fallback;
        return Math.max(8, Math.min(100, number));
    }
    function renderCommercialRuleBuilder(root, config, activeRule) {
        if (!root) return;
        const message = arguments.length > 3 ? arguments[3] : '';
        const rules = config?.rules || [];
        const rule = rules.find(item => item.id === activeRule) || rules[0] || {};
        root.className = `commercial-rule-builder ${config?.tone || ''}`.trim();
        root.dataset.commercialRuleActive = rule.id || '';
        root.innerHTML = `
            <div class="commercial-rule-copy">
                <span>Alert Rule Builder</span>
                <strong>${escapeHtml(config?.title || 'Rule Builder')}</strong>
                <em>${escapeHtml(rule.detail || config?.detail || '')}</em>
                <div class="commercial-rule-presets">
                    ${rules.map(item => `<button class="commercial-rule-button ${item.id === rule.id ? 'is-active' : ''}" type="button" data-commercial-rule-preset="${escapeHtml(item.id)}" aria-pressed="${item.id === rule.id}">${escapeHtml(item.label)}</button>`).join('')}
                </div>
            </div>
            <div class="commercial-rule-controls" aria-label="Alert rule builder">
                ${(rule.controls || []).map(control => `
                    <div class="commercial-rule-control">
                        <span>${escapeHtml(control.label)}</span>
                        <strong>${escapeHtml(control.value)}</strong>
                        <i style="--w:${escapeHtml(ruleControlWidth(control.strength, 52))}%"></i>
                    </div>
                `).join('')}
            </div>
            <div class="commercial-rule-status">
                <strong>${escapeHtml(rule.summary || config?.summary || 'Rule ready')}</strong>
                <em>${escapeHtml(rule.recovery || '儲存後可做為後續告警 API 的規則草稿。')}</em>
                <div class="commercial-rule-metrics">
                    ${(rule.metrics || []).map(metric => `
                        <div class="commercial-rule-metric">
                            <span>${escapeHtml(metric.label)}</span>
                            <strong>${escapeHtml(metric.value)}</strong>
                        </div>
                    `).join('')}
                </div>
                <div class="commercial-rule-actions">
                    <button class="commercial-rule-action is-primary" type="button" data-commercial-rule-save="${escapeHtml(rule.id || '')}">Save Rule</button>
                    <button class="commercial-rule-action" type="button" data-commercial-rule-copy="${escapeHtml(rule.id || '')}">Copy Rule</button>
                    <button class="commercial-rule-action" type="button" data-commercial-rule-target="${escapeHtml(rule.target || config?.target || '')}">Open Source</button>
                </div>
                <span class="commercial-rule-feedback" data-commercial-rule-feedback role="status" aria-live="polite">${escapeHtml(message)}</span>
            </div>
        `;
    }
    function commercialRuleSummary(config, rule) {
        return [
            config?.title || 'Alert rule',
            rule?.label || 'Rule',
            rule?.summary || '',
            ...(rule?.controls || []).map(control => `${control.label}: ${control.value}`)
        ].filter(Boolean).join('\n');
    }
    function bindCommercialRuleBuilder(root, scope, configFactory) {
        if (!root || root.dataset.commercialRuleBuilderBound === 'true') return;
        root.dataset.commercialRuleBuilderBound = 'true';
        root.addEventListener('click', event => {
            const config = typeof configFactory === 'function' ? configFactory() : {};
            const fallbackRule = config?.rules?.[0]?.id || 'default';
            const preset = event.target.closest('[data-commercial-rule-preset]')?.dataset.commercialRulePreset;
            const save = event.target.closest('[data-commercial-rule-save]')?.dataset.commercialRuleSave;
            const copy = event.target.closest('[data-commercial-rule-copy]')?.dataset.commercialRuleCopy;
            const target = event.target.closest('[data-commercial-rule-target]')?.dataset.commercialRuleTarget;
            const nextRule = preset || save || copy || root.dataset.commercialRuleActive || commercialRulePreference(scope, fallbackRule);
            const rule = config?.rules?.find(item => item.id === nextRule) || config?.rules?.[0] || {};
            if (preset) {
                writeCommercialMemory(`rule-builder-${scope}`, { rule: preset });
                renderCommercialRuleBuilder(root, config, preset);
                return;
            }
            if (save) {
                writeCommercialMemory(`rule-builder-${scope}`, { rule: save, savedAt: new Date().toLocaleString('zh-TW', { hour12: false }) });
                renderCommercialRuleBuilder(root, config, save, 'Rule saved');
                return;
            }
            if (copy) {
                copyCommercialText(commercialRuleSummary(config, rule), root, 'Rule copied');
                const status = root.querySelector('[data-commercial-rule-feedback]');
                if (status) status.textContent = 'Rule copied';
                return;
            }
            if (target) {
                scrollCommercialTaskTarget(target);
                return;
            }
            renderCommercialRuleBuilder(root, config, commercialRulePreference(scope, fallbackRule));
        });
    }
