    function commercialGridPreference(scope, fallbackView, fallbackSort) {
        const saved = readCommercialMemory(`grid-lab-${scope}`);
        return {
            view: saved.view || fallbackView,
            sort: saved.sort || fallbackSort || { key: 'score', direction: 'desc' }
        };
    }
    function commercialGridCell(row, key) {
        const cell = row?.cells?.[key];
        if (cell && typeof cell === 'object') return cell;
        return { value: cell ?? row?.[key] ?? '', raw: cell ?? row?.[key] ?? '' };
    }
    function commercialGridSortRows(rows, sortState) {
        const state = sortState || { key: 'score', direction: 'desc' };
        const direction = state.direction === 'asc' ? 1 : -1;
        return [...(rows || [])].sort((left, right) => {
            const leftValue = commercialGridCell(left, state.key).raw;
            const rightValue = commercialGridCell(right, state.key).raw;
            const leftNumber = Number(leftValue);
            const rightNumber = Number(rightValue);
            if (Number.isFinite(leftNumber) && Number.isFinite(rightNumber)) return (leftNumber - rightNumber) * direction;
            return String(leftValue ?? '').localeCompare(String(rightValue ?? ''), 'zh-Hant') * direction;
        });
    }
    function commercialGridCsv(config, view) {
        const columns = view?.columns || [];
        const headers = columns.map(column => column.label);
        const escapeCsv = value => `"${String(value ?? '').replaceAll('"', '""')}"`;
        const rows = (view?.rows || []).map(row => columns.map(column => escapeCsv(commercialGridCell(row, column.key).value)).join(','));
        return [config?.title || 'Advanced Data Grid', headers.join(','), ...rows].join('\n');
    }
    function renderCommercialGridLab(root, config, activeView, sortState) {
        if (!root) return;
        const secondaryState = commercialSecondaryRenderState(root);
        const views = config?.views || [];
        const view = views.find(item => item.id === activeView) || views[0] || {};
        const columns = view.columns || [];
        const currentSort = sortState || view.defaultSort || { key: columns[0]?.key || 'name', direction: 'asc' };
        const sortedRows = commercialGridSortRows(view.rows || [], currentSort);
        root.className = `commercial-grid-lab ${config?.tone || ''}`.trim();
        root.dataset.commercialGridActive = view.id || '';
        root.dataset.commercialGridSortKey = currentSort.key || '';
        root.dataset.commercialGridSortDirection = currentSort.direction || 'desc';
        root.innerHTML = `
            ${secondaryState.toggleHtml}
            <div class="commercial-grid-copy">
                <span>Advanced Data Grid</span>
                <strong>${escapeHtml(config?.title || 'Data Grid')}</strong>
                <em>${escapeHtml(view.detail || config?.detail || '')}</em>
                <div class="commercial-grid-views">
                    ${views.map(item => `<button class="commercial-grid-view-button ${item.id === view.id ? 'is-active' : ''}" type="button" data-commercial-grid-view="${escapeHtml(item.id)}" aria-pressed="${item.id === view.id}">${escapeHtml(item.label)}</button>`).join('')}
                </div>
            </div>
            <div class="commercial-grid-table">
                <table aria-label="Advanced data grid">
                    <thead><tr>
                        ${columns.map(column => {
                            const active = currentSort.key === column.key;
                            const nextDirection = active && currentSort.direction === 'desc' ? 'asc' : 'desc';
                            const ariaSort = active ? (currentSort.direction === 'asc' ? 'ascending' : 'descending') : 'none';
                            return `<th aria-sort="${escapeHtml(ariaSort)}"><button class="commercial-grid-sort-button" type="button" data-commercial-grid-sort="${escapeHtml(column.key)}" data-commercial-grid-direction="${escapeHtml(nextDirection)}">${escapeHtml(column.label)}<span>${escapeHtml(active ? (currentSort.direction === 'asc' ? '↑' : '↓') : '↕')}</span></button></th>`;
                        }).join('')}
                    </tr></thead>
                    <tbody>
                        ${sortedRows.map(row => `<tr>${columns.map(column => {
                            const cell = commercialGridCell(row, column.key);
                            return `<td>${column.emphasis ? `<strong>${escapeHtml(cell.value)}</strong>` : escapeHtml(cell.value)}</td>`;
                        }).join('')}</tr>`).join('')}
                    </tbody>
                </table>
            </div>
            <div class="commercial-grid-summary">
                <strong>${escapeHtml(view.summary || `${sortedRows.length} rows`)}</strong>
                <em>${escapeHtml(view.readout || 'Sortable table view with saved layout state.')}</em>
                <div class="commercial-grid-summary-grid">
                    ${(view.metrics || []).map(metric => `<div class="commercial-grid-summary-item"><span>${escapeHtml(metric.label)}</span><strong>${escapeHtml(metric.value)}</strong></div>`).join('')}
                </div>
                <div class="commercial-grid-actions">
                    <button class="commercial-grid-action is-primary" type="button" data-commercial-grid-save>Save Grid View</button>
                    <button class="commercial-grid-action" type="button" data-commercial-grid-export>Export CSV</button>
                    <button class="commercial-grid-action" type="button" data-commercial-grid-target="${escapeHtml(view.target || config?.target || '')}">Open Source</button>
                </div>
                <span class="commercial-grid-feedback" data-commercial-grid-feedback role="status" aria-live="polite"></span>
            </div>
        `;
        restoreCommercialSecondaryRenderState(root, secondaryState);
    }
    function bindCommercialGridLab(root, scope, configFactory) {
        if (!root || root.dataset.commercialGridLabBound === 'true') return;
        root.dataset.commercialGridLabBound = 'true';
        root.addEventListener('click', event => {
            const config = typeof configFactory === 'function' ? configFactory() : {};
            const fallbackView = config?.views?.[0]?.id || 'default';
            const fallbackSort = config?.views?.[0]?.defaultSort || { key: 'score', direction: 'desc' };
            const preference = commercialGridPreference(scope, fallbackView, fallbackSort);
            const viewId = event.target.closest('[data-commercial-grid-view]')?.dataset.commercialGridView || preference.view;
            const sortButton = event.target.closest('[data-commercial-grid-sort]');
            const target = event.target.closest('[data-commercial-grid-target]')?.dataset.commercialGridTarget;
            const activeView = config?.views?.find(item => item.id === viewId) || config?.views?.[0] || {};
            const sort = sortButton
                ? { key: sortButton.dataset.commercialGridSort, direction: sortButton.dataset.commercialGridDirection || 'desc' }
                : preference.sort || activeView.defaultSort || fallbackSort;
            if (event.target.closest('[data-commercial-grid-view]') || sortButton) {
                writeCommercialMemory(`grid-lab-${scope}`, { view: activeView.id, sort });
                renderCommercialGridLab(root, config, activeView.id, sort);
                return;
            }
            if (event.target.closest('[data-commercial-grid-save]')) {
                writeCommercialMemory(`grid-lab-${scope}`, { view: activeView.id, sort });
                renderCommercialGridLab(root, config, activeView.id, sort);
                const status = root.querySelector('[data-commercial-grid-feedback]');
                if (status) status.textContent = 'Grid view saved';
                return;
            }
            if (event.target.closest('[data-commercial-grid-export]')) {
                copyCommercialText(commercialGridCsv(config, activeView), root, 'Grid CSV copied');
                const status = root.querySelector('[data-commercial-grid-feedback]');
                if (status) status.textContent = 'Grid CSV copied';
                return;
            }
            if (target) scrollCommercialTaskTarget(target);
        });
    }
