    function bindCommercialGlobalContext(pageName, getTicker, onTicker) {
        const root = document.getElementById('commercial-global-context');
        if (!root) return null;
        renderCommercialGlobalContext(root, { pageName, ticker: typeof getTicker === 'function' ? getTicker() : readCommercialParams().get('ticker') });
        if (root.dataset.commercialContextBound === 'true') return root;
        root.dataset.commercialContextBound = 'true';
        root.addEventListener('submit', async event => {
            event.preventDefault();
            const input = root.querySelector('[data-commercial-context-input]');
            const contextTicker = syncCommercialContextTicker(input?.value || (typeof getTicker === 'function' ? getTicker() : '2330.TW'));
            renderCommercialGlobalContext(root, { pageName, ticker: contextTicker });
            if (typeof onTicker === 'function') await onTicker(contextTicker);
        });
        root.addEventListener('click', async event => {
            const button = event.target.closest('[data-commercial-context-target]');
            if (!button) return;
            const input = root.querySelector('[data-commercial-context-input]');
            const contextTicker = syncCommercialContextTicker(input?.value || (typeof getTicker === 'function' ? getTicker() : '2330.TW'));
            const target = button.dataset.commercialContextTarget;
            if (target === commercialContextTargetId(pageName)) {
                renderCommercialGlobalContext(root, { pageName, ticker: contextTicker });
                if (typeof onTicker === 'function') await onTicker(contextTicker);
                return;
            }
            window.location.href = commercialPageUrl(target, contextTicker);
        });
        return root;
    }
