    function fallbackCopyCommercialText(text) {
        const textarea = document.createElement('textarea');
        textarea.value = String(text || '');
        textarea.setAttribute('readonly', '');
        textarea.style.position = 'fixed';
        textarea.style.top = '-9999px';
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand('copy');
        textarea.remove();
    }
    async function copyCommercialText(text, root, successLabel) {
        try {
            if (navigator.clipboard?.writeText && window.isSecureContext) await navigator.clipboard.writeText(String(text || ''));
            else fallbackCopyCommercialText(text);
            showCommercialFeedback(root, successLabel || '已複製');
        } catch (_) {
            showCommercialFeedback(root, '已準備複製內容');
        }
    }
    function downloadCommercialText(filename, text) {
        const blob = new Blob([String(text || '')], { type: 'text/plain;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        link.remove();
        URL.revokeObjectURL(url);
    }
