        const config = workbenchScreenPresetConfig(activePreset);
        const candidates = [
            { ticker: '2454.TW', company: '聯發科', theme: 'AI edge devices', returnPct: 3.6, quality: 86, event: '法說 14 天' },
            { ticker: '2412.TW', company: '中華電', theme: 'defensive yield', returnPct: 1.8, quality: 82, event: '除息 28 天' },
            { ticker: 'NVDA', company: 'NVIDIA', theme: 'AI infrastructure', returnPct: 5.4, quality: 91, event: '財報 21 天' },
            { ticker: 'AAPL', company: 'Apple', theme: 'consumer cycle', returnPct: 0.9, quality: 78, event: '產品發表' }
        ].filter(candidate => !tracked.has(normalizeTicker(candidate.ticker)));
        const radarRows = (candidates.length ? candidates : fallbackTickers).slice(0, 4).map((candidate, index) => {
            const momentum = Number(candidate.returnPct) || (index + 1) * 1.2;
            const quality = Number(candidate.quality) || (workbenchPlainValue(candidate, 'quality') === 'Fresh' ? 80 : 68);
            const screenScore = Math.round(Math.max(42, Math.min(98, quality * 0.58 + Math.max(0, momentum) * 6 + (config.columnSet === 'event' ? 8 : 0))));
            return { ...candidate, screenScore };
        }).sort((left, right) => right.screenScore - left.screenScore);
