    function renderStockAnalystBreakdown(snapshot) {
        const root = document.getElementById('commercial-stock-analyst-breakdown');
        if (!root) return;
        const upside = Number(snapshot.analyst_outlook?.target?.upside_pct);
        const qualityScore = Number(snapshot.data_quality?.score) || 78;
        const consensus = String(snapshot.analyst_outlook?.consensus?.recommendation_label || snapshot.analyst_outlook?.label || '').toLowerCase();
        const strongBuy = consensus.includes('強') || (Number.isFinite(upside) && upside >= 12) ? 7 : qualityScore >= 88 ? 5 : 3;
        const buy = Number.isFinite(upside) && upside >= 7 ? 6 : 4;
        const hold = Math.max(2, 8 - Math.round((Number.isFinite(upside) ? upside : 5) / 3));
        const sell = qualityScore < 70 || (Number.isFinite(upside) && upside < 0) ? 2 : 1;
        const ratings = [
            ['Strong Buy', strongBuy, '高信心買進'],
            ['Buy', buy, '正向評等'],
            ['Hold', hold, '中立等待'],
            ['Sell', sell, '保守或降評']
        ];
        const total = ratings.reduce((sum, [, count]) => sum + count, 0) || 1;
        const leader = ratings.reduce((best, row) => row[1] > best[1] ? row : best, ratings[0]);
        root.innerHTML = `
            <div class="commercial-action-title">Analyst Rating Breakdown</div>
            <div class="commercial-analyst-breakdown">
                <div class="commercial-analyst-summary">
                    <span>Consensus Cluster</span>
                    <strong>${escapeHtml(leader[0])}</strong>
                    <em>${escapeHtml(`${leader[1]} / ${total} ratings · 近 30-90 天評等分布`)}</em>
                </div>
                ${ratings.map(([label, count, detail]) => `
                    <div data-analyst-rating="${escapeHtml(label)}">
                        <span>${escapeHtml(label)}</span>
                        <i class="commercial-analyst-rating-bar" style="--w:${escapeHtml((count / total) * 100)}%"></i>
                        <strong>${escapeHtml(count)}</strong>
                        <em>${escapeHtml(detail)}</em>
                    </div>
                `).join('')}
            </div>
        `;
    }
