    function gradeLetter(score) {
        if (score >= 85) return 'A';
        if (score >= 72) return 'B';
        if (score >= 58) return 'C';
        return 'D';
    }
    function renderStockRatingExplainability(snapshot) {
        const root = document.getElementById('commercial-stock-rating-explainability');
        if (!root) return;
        const qualityScore = Number(snapshot.data_quality?.score) || 78;
        const upside = Number(snapshot.analyst_outlook?.target?.upside_pct);
        const momentumScore = snapshot.market_session?.direction === 'up' ? 82 : 61;
        const factors = [
            ['Value', 68, 20, 'current valuation vs sector'],
            ['Growth', 74, 18, 'revenue and EPS trajectory'],
            ['Profitability', qualityScore, 24, 'margin and ROE quality'],
            ['Momentum', momentumScore, 18, 'price trend and volume'],
            ['EPS Revisions', Number.isFinite(upside) && upside > 10 ? 84 : 66, 20, 'estimate revision timeliness']
        ];
        const weightedScore = factors.reduce((sum, [, score, weight]) => sum + score * weight / 100, 0);
        const sectorAverage = Math.max(45, Math.min(82, weightedScore - 6 + (snapshot.identity?.sector === 'Technology' ? 2 : 0)));
        const disqualifier = factors.find(([, score]) => score < 58);
        root.innerHTML = `
            <div class="commercial-action-title">Rating Explainability</div>
            <div class="commercial-rating-explainability">
                <div class="commercial-rating-explain-summary">
                    <span>Quant Score</span>
                    <strong>${escapeHtml(weightedScore.toFixed(1))}</strong>
                    <em>${escapeHtml(`Sector Average ${sectorAverage.toFixed(1)} · ${disqualifier ? 'Disqualifier Check failed' : 'Disqualifier Check clear'}`)}</em>
                </div>
                ${factors.map(([label, score, weight, detail]) => `
                    <div class="commercial-rating-factor" data-rating-explainability="${escapeHtml(label)}">
                        <span>${escapeHtml(label)}</span>
                        <i style="--w:${escapeHtml(Math.max(8, Math.min(100, score)))}%"></i>
                        <strong>${escapeHtml(`${gradeLetter(score)} · ${weight}%`)}</strong>
                        <em>${escapeHtml(`Factor Weight ${weight}% · ${detail}`)}</em>
                    </div>
                `).join('')}
            </div>
        `;
    }
