            setStockRange(activeRange);
            setStockScenario(activeScenario);
            setStockAlertPreset(activeAlertPreset);
            syncStockUrl(normalized);
            renderStockDelivery(document.getElementById('commercial-stock-delivery'), snapshot, currentTab, activeScenario, activeRange);
