    function renderPortfolioDriftPanel(payload, activeTargetModel = 'balanced', driftTolerance = 5) {
        const root = document.getElementById('commercial-portfolio-drift-panel');
        if (!root) return;
        const model = PORTFOLIO_TARGET_MODELS[activeTargetModel] || PORTFOLIO_TARGET_MODELS.balanced;
        const current = payload.concentration?.sector_weights || {};
        const driftRows = Object.entries(model.targets).map(([label, target]) => {
            const actual = Number(current[label] || 0);
            return [label, actual, Number(target), actual - Number(target)];
        }).sort((left, right) => Math.abs(right[3]) - Math.abs(left[3]));
        const totalDrift = driftRows.reduce((sum, row) => sum + Math.abs(row[3]), 0) / 2;
        const largest = driftRows[0] || ['N/A', 0, 0, 0];
        const breaches = driftRows.filter(row => Math.abs(row[3]) > driftTolerance).length;
        root.innerHTML = `
            <div class="commercial-action-title">Target Drift</div>
            <div class="commercial-drift-panel">
                <div><span>Model</span><strong>${escapeHtml(model.label)}</strong><em>最大持股目標 ${escapeHtml(model.maxPosition)}%</em></div>
                <div><span>Total Drift</span><strong>${escapeHtml(pct(totalDrift).replace('+', ''))}</strong><em>距離目標配置的總偏離</em></div>
                <div><span>Tolerance Breaches</span><strong>${escapeHtml(breaches)}</strong><em>${escapeHtml(driftTolerance)}% tolerance · largest ${escapeHtml(largest[0])} ${escapeHtml(pct(largest[3]))}</em></div>
            </div>
        `;
    }
