        function portfolioRebalanceState(extra = {}) {
            return { portfolioContextTicker, activeLens, activeScenario, targetWeight, driftTolerance, activeExecutionMode, activeTargetModel, ...extra };
        }
        function renderPortfolioHistory(message = '') {
            portfolioHistoryMessage = message || portfolioHistoryMessage;
            renderPortfolioRebalanceHistory(document.getElementById('commercial-portfolio-rebalance-history'), lastPayload, { activeLens, activeScenario, targetWeight, activeExecutionMode, activeTargetModel }, portfolioHistoryMessage);
            renderPortfolioClientPack(document.getElementById('commercial-portfolio-client-pack'), lastPayload, activeLens, activeScenario, activeTargetModel);
        }
        function selectPortfolioLens(nextLens, options = {}) {
            const portfolioLens = validCommercialChoice(nextLens, ['sector', 'country', 'risk', 'contribution'], activeLens);
            activeLens = portfolioLens;
            applyPortfolioTargetWeight(lastPayload, activeLens, activeScenario, targetWeight, activeExecutionMode, activeTargetModel, driftTolerance, portfolioSource);
            renderCommercialProvenance(portfolioProvenanceRoot, portfolioProvenanceItems(portfolioSource, lastPayload, activeTargetModel));
            syncPortfolioUrl();
            renderPortfolioWorkspaceChrome();
            renderPortfolioHistory(options.historyMessage);
            requestAnimationFrame(() => scrollCommercialElementTarget(options.target || 'commercial-portfolio-health-score'));
        }
        function savePortfolioRebalanceState(message = 'Scenario checkpoint copied') {
            writeCommercialMemory('portfolio-rebalance', portfolioRebalanceState());
            renderPortfolioHistory(message);
        }
        function restorePortfolioRebalanceState(savedPortfolioState) {
            if (!savedPortfolioState || !savedPortfolioState.activeTargetModel) {
                renderPortfolioHistory('No saved scenario yet');
                return;
            }
            portfolioContextTicker = normalizeTicker(savedPortfolioState.portfolioContextTicker || portfolioContextTicker);
            activeLens = validCommercialChoice(savedPortfolioState.activeLens, ['sector', 'country', 'risk', 'contribution'], activeLens);
            activeScenario = validCommercialChoice(savedPortfolioState.activeScenario, ['base', 'rate', 'chip', 'fx'], activeScenario);
            targetWeight = Number(savedPortfolioState.targetWeight) || targetWeight;
            driftTolerance = Number(savedPortfolioState.driftTolerance) || driftTolerance;
            activeExecutionMode = validCommercialChoice(savedPortfolioState.activeExecutionMode, ['trim', 'cash', 'balanced'], activeExecutionMode);
            activeTargetModel = validCommercialChoice(savedPortfolioState.activeTargetModel, Object.keys(PORTFOLIO_TARGET_MODELS), activeTargetModel);
            applyPortfolioTargetWeight(lastPayload, activeLens, activeScenario, targetWeight, activeExecutionMode, activeTargetModel, driftTolerance, portfolioSource);
            renderCommercialProvenance(portfolioProvenanceRoot, portfolioProvenanceItems(portfolioSource, lastPayload, activeTargetModel));
            syncPortfolioUrl();
            renderPortfolioHistory('Restored previous scenario');
        }
