        async function analyze() {
            renderCommercialDataStatus(portfolioDataStatusRoot, portfolioDataStatus('loading', lastPayload));
            try {
                lastPayload = await jsonRequest('/api/watchlist/portfolio/risk', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ csv: csvInput?.value || '', thesis_health: { missing: ['AAPL'], invalidated: ['1623.TW'] } }) });
                portfolioSource = 'live';
            } catch (_) {
                portfolioSource = 'fallback';
                lastPayload = fallbackPortfolio;
            }
            if (!params.has('ticker')) portfolioContextTicker = normalizeTicker(lastPayload.concentration?.top_position?.ticker || portfolioContextTicker);
            applyPortfolioTargetWeight(lastPayload, activeLens, activeScenario, targetWeight, activeExecutionMode, activeTargetModel, driftTolerance, portfolioSource);
            renderCommercialDataStatus(portfolioDataStatusRoot, portfolioDataStatus(portfolioSource, lastPayload));
            renderCommercialProvenance(portfolioProvenanceRoot, portfolioProvenanceItems(portfolioSource, lastPayload, activeTargetModel));
            syncPortfolioUrl();
            renderPortfolioWorkspaceChrome();
            renderPortfolioHistory();
        }
