    document.addEventListener('DOMContentLoaded', () => {
        const page = document.body.dataset.commercialPage;
        const loader =
            page === 'research-workbench' ? loadResearchWorkbench :
            page === 'stock-detail' ? loadStockDetail :
            page === 'portfolio-dashboard' ? loadPortfolioDashboard :
            null;
        Promise.resolve().then(() => loader?.()).finally(() => {
            setupCommercialSecondaryModules(page);
            const scope = document.querySelector('.commercial-main') || document.body;
            installCommercialVisibleTextObserver(scope);
            translateCommercialVisibleText(scope);
        });
    });
